args.query:
WITH arca_etf AS (
  SELECT Symbol FROM sqlite_scan('stockinfo_database', 'stockinfo')
  WHERE "Listing Exchange"='P' AND ETF='Y' AND "Test Issue"='N'
), max2015 AS (
  SELECT t.table_name AS Symbol,
         (SELECT MAX("Adj Close") FROM (SELECT * FROM "main"."' || t.table_name || '")) AS dummy
  FROM information_schema.tables t
)
SELECT 1;

